/**
 * Protocol dispatcher for pushing analyzer results during E2E demos.
 *
 * Routes to the correct push mechanism based on protocol:
 * - ASTM: POST to simulator /simulate/astm/{template}
 * - HL7:  POST to simulator /simulate/hl7/{template}
 * - FILE: Copy fixture file to import directory
 *
 * Returns the sample_id generated by the mock (unique per push).
 * The test uses this to verify results on AnalyzerResults/AccessionResults.
 */

import { execFileSync } from "child_process";
import { expect, Page } from "@playwright/test";
import * as fs from "fs";
import * as path from "path";
import type { DemoPresentation } from "./demo-presentation";
import type { PushConfig } from "./analyzer-test-config";

const E2E_FIXTURES_DIR =
  process.env.E2E_FIXTURES_DIR || path.resolve(__dirname, "../fixtures");
const HOST_IMPORTS_SEGMENT =
  path.normalize("projects/analyzer-harness/volume/analyzer-imports") +
  path.sep;
const CONTAINER_IMPORTS_BASE = "/data/analyzer-imports";
const BRIDGE_CONTAINER =
  process.env.ANALYZER_BRIDGE_CONTAINER || "openelis-analyzer-bridge";

function ensureFileImportDirWritable(importDir: string): void {
  fs.mkdirSync(importDir, { recursive: true });
  try {
    fs.accessSync(importDir, fs.constants.W_OK);
    return;
  } catch {
    // The bridge may have created the bind-mounted directory as root on CI.
    // Fix it through the container mount, then re-check host writability.
  }

  const normalizedImportDir = path.normalize(importDir);
  const markerIndex = normalizedImportDir.lastIndexOf(HOST_IMPORTS_SEGMENT);
  if (markerIndex !== -1) {
    const relativeImportDir = normalizedImportDir.slice(
      markerIndex + HOST_IMPORTS_SEGMENT.length,
    );
    const containerImportDir = path.posix.join(
      CONTAINER_IMPORTS_BASE,
      relativeImportDir.split(path.sep).join("/"),
    );
    execFileSync("docker", [
      "exec",
      BRIDGE_CONTAINER,
      "sh",
      "-lc",
      `mkdir -p '${containerImportDir}' && chmod -R a+rwX '${containerImportDir}'`,
    ]);
  }

  fs.accessSync(importDir, fs.constants.W_OK);
}

/**
 * Push a result to the mock analyzer and return the generated sample_id.
 * The mock generates unique sequential IDs per template (like a real analyzer).
 */
export async function pushAnalyzerResult(
  page: Page,
  push: PushConfig,
  presentation: DemoPresentation,
): Promise<string | null> {
  switch (push.protocol) {
    case "ASTM": {
      const response = await page.request.post(
        `${push.simulatorUrl}/simulate/astm/${push.template}`,
        {
          data: {
            destination: push.destination,
            count: 1,
            ...(push.sampleId ? { sample_id: push.sampleId } : {}),
          },
        },
      );
      expect(response.ok()).toBeTruthy();
      await presentation.pause(1_000);
      // Extract sample_id from response if available
      try {
        const body = await response.json();
        return body?.results?.[0]?.sample_id ?? null;
      } catch {
        return null;
      }
    }

    case "HL7": {
      const response = await page.request.post(
        `${push.simulatorUrl}/simulate/hl7/${push.template}`,
        {
          data: {
            destination: push.destination,
            count: 1,
            ...(push.sampleId ? { sample_id: push.sampleId } : {}),
          },
        },
      );
      expect(response.ok()).toBeTruthy();
      await presentation.pause(1_000);
      // Extract sample_id from response
      try {
        const body = await response.json();
        return body?.results?.[0]?.sample_id ?? null;
      } catch {
        return null;
      }
    }

    case "FILE": {
      const fixturePath = path.resolve(E2E_FIXTURES_DIR, push.fixtureFile);
      if (!fs.existsSync(fixturePath)) {
        throw new Error(
          `Fixture file not found: ${fixturePath} (set E2E_FIXTURES_DIR if non-default)`,
        );
      }

      ensureFileImportDirWritable(push.importDir);
      const ext = path.extname(push.fixtureFile);
      const destFile = path.join(
        push.importDir,
        `${push.filePrefix}${Date.now()}${ext}`,
      );

      // Copy fixture and append unique bytes so the bridge's content-hash
      // deduplication doesn't skip it on re-runs. Excel/BIFF ignores trailing data.
      const fixtureData = fs.readFileSync(fixturePath);
      const uniqueSuffix = Buffer.from(`\n<!-- e2e-run-${Date.now()} -->`);
      fs.writeFileSync(destFile, Buffer.concat([fixtureData, uniqueSuffix]));

      await presentation.pause(2_000); // Wait for file watcher to pick up
      return null; // FILE protocol doesn't return sample_id from mock
    }
  }
}
